// ==================================================
//  pages/Designs.jsx — عرض التصاميم + التقييم
// ==================================================
import React, { useState, useEffect } from 'react'
import { getDesigns } from '../services/designService'

export default function Designs() {
  const [designs, setDesigns]   = useState([])
  const [loading, setLoading]   = useState(true)
  const [ratings, setRatings]   = useState({})   // تقييمات محلية
  const [filter, setFilter]     = useState('all')

  useEffect(() => {
    fetchDesigns()
  }, [])

  const fetchDesigns = async () => {
    try {
      const data = await getDesigns()
      setDesigns(data)
    } catch {
      // إذا الـ Backend غير شغال، نعرض بيانات تجريبية
      setDesigns(SAMPLE_DESIGNS)
    } finally {
      setLoading(false)
    }
  }

  const handleRate = (designId, star) => {
    setRatings(prev => ({ ...prev, [designId]: star }))
  }

  if (loading) return <div className="page-center"><div className="spinner" /></div>

  return (
    <div style={styles.page}>
      {/* Header */}
      <div style={styles.header}>
        <h1 style={styles.title}>معرض التصاميم</h1>
        <p style={styles.sub}>اكتشف تصاميم فريدة صُنعت بالذكاء الاصطناعي</p>

        {/* فلتر */}
        <div style={styles.filters}>
          {['all', 'فساتين', 'قمصان', 'بناطيل', 'عبايات'].map(f => (
            <button
              key={f}
              onClick={() => setFilter(f)}
              className="btn"
              style={{
                ...styles.filterBtn,
                background: filter === f ? '#0a0a0a' : '#fff',
                color:      filter === f ? '#fff'    : '#333',
              }}
            >
              {f === 'all' ? 'الكل' : f}
            </button>
          ))}
        </div>
      </div>

      {/* شبكة التصاميم */}
      <div style={styles.grid}>
        {designs.map(design => (
          <DesignCard
            key={design.id}
            design={design}
            userRating={ratings[design.id] || 0}
            onRate={(star) => handleRate(design.id, star)}
          />
        ))}
      </div>

      {designs.length === 0 && (
        <div style={styles.empty}>
          <span style={{fontSize: 60}}>👗</span>
          <p>لا توجد تصاميم بعد</p>
        </div>
      )}
    </div>
  )
}

// ===== كارد التصميم =====
function DesignCard({ design, userRating, onRate }) {
  const [liked, setLiked] = useState(false)
  const [showOrder, setShowOrder] = useState(false)

  return (
    <div style={styles.card}>
      {/* صورة التصميم */}
      <div style={styles.imageBox}>
        {design.image ? (
          <img src={design.image} alt={design.title} style={styles.image} />
        ) : (
          <div style={styles.imagePlaceholder}>
            <span style={{fontSize: 60}}>👗</span>
          </div>
        )}
        {/* زر الإعجاب */}
        <button
          onClick={() => setLiked(!liked)}
          style={{ ...styles.likeBtn, color: liked ? '#e74c3c' : '#999' }}
        >
          {liked ? '❤️' : '🤍'}
        </button>
      </div>

      {/* معلومات */}
      <div style={styles.info}>
        <h3 style={styles.designTitle}>{design.title}</h3>
        <p style={styles.designDesc}>{design.description}</p>

        {/* التقييم بالنجوم */}
        <div style={styles.stars}>
          <span style={styles.starsLabel}>تقييمك:</span>
          {[1,2,3,4,5].map(star => (
            <button
              key={star}
              onClick={() => onRate(star)}
              style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: 20, padding: '0 2px' }}
            >
              {star <= userRating ? '⭐' : '☆'}
            </button>
          ))}
        </div>

        {/* السعر والطلب */}
        <div style={styles.bottom}>
          <span style={styles.price}>{design.price} ر.س</span>
          <button
            onClick={() => setShowOrder(true)}
            className="btn btn-primary"
            style={{ padding: '8px 20px', fontSize: 13 }}
          >
            اطلب الآن
          </button>
        </div>
      </div>

      {/* نافذة الطلب */}
      {showOrder && (
        <OrderModal design={design} onClose={() => setShowOrder(false)} />
      )}
    </div>
  )
}

// ===== نافذة الطلب =====
function OrderModal({ design, onClose }) {
  const [address, setAddress]   = useState('')
  const [quantity, setQuantity] = useState(1)
  const [done, setDone]         = useState(false)

  const submit = () => {
    if (!address) return alert('أدخل عنوان التوصيل')
    // هنا تستدعي orderService.createOrder(...)
    setDone(true)
  }

  return (
    <div style={styles.overlay}>
      <div style={styles.modal}>
        {done ? (
          <div style={{textAlign:'center', padding: 20}}>
            <p style={{fontSize: 50}}>✅</p>
            <h3 style={{fontFamily:"'Playfair Display',serif", fontSize: 24, margin: '16px 0 8px'}}>تم الطلب!</h3>
            <p style={{color:'#888', marginBottom: 24}}>سنتواصل معك قريباً</p>
            <button onClick={onClose} className="btn btn-primary">إغلاق</button>
          </div>
        ) : (
          <>
            <h3 style={styles.modalTitle}>طلب: {design.title}</h3>
            <div style={styles.field}>
              <label style={styles.label}>الكمية</label>
              <input
                type="number" min="1" max="10"
                value={quantity}
                onChange={e => setQuantity(e.target.value)}
                className="input"
              />
            </div>
            <div style={styles.field}>
              <label style={styles.label}>عنوان التوصيل</label>
              <textarea
                value={address}
                onChange={e => setAddress(e.target.value)}
                placeholder="المدينة، الحي، الشارع..."
                className="input"
                rows={3}
                style={{resize:'none'}}
              />
            </div>
            <p style={{color:'#c9a84c', fontWeight:600, marginBottom:16}}>
              الإجمالي: {design.price * quantity} ر.س
            </p>
            <div style={{display:'flex', gap:10}}>
              <button onClick={submit}  className="btn btn-primary" style={{flex:1}}>تأكيد الطلب</button>
              <button onClick={onClose} className="btn btn-outline" style={{flex:1}}>إلغاء</button>
            </div>
          </>
        )}
      </div>
    </div>
  )
}

